# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

@app.route('/api/search', methods=['GET'])
def search_products():
    query = request.args.get('q')
    
    if not query:
        return jsonify({'error': 'Missing required parameter: q'}), 400
    
    try:
        body = {
            "query": {
                "multi_match": {
                    "fields": ["title^5", "description"],
                    "query": query,
                    "minimum_should_match_script": {
                        "source": "doc['description'].length"
                    }
                }
            }
        }
        
        response = es.search(index='products', body=body)
        
        if 'hits' in response and len(response['hits']['hits']) > 0:
            products = [{'id': hit['_source']['id'], 'title': hit['_source']['title']} for hit in response['hits']['hits']]
            return jsonify({'products': products}), 200
        else:
            return jsonify({'error': 'No matching products found'}), 404
    
    except Exception as e:
        print(f"Error: {e}")
        return jsonify({'error': 'Internal Server Error'}), 500

if __name__ == '__main__':
    app.run(debug=True)